import{_ as e,o as i,c as t,a}from"./app.b5e328ff.js";var r="/aktivitaeten/BDM-2026-03/00_03-2026.jpg",n="/aktivitaeten/BDM-2026-03/01_03-2026.jpg",s="/aktivitaeten/BDM-2026-03/02_03-2026.jpg",d="/aktivitaeten/BDM-2026-03/03_03-2026.jpg",l="/aktivitaeten/BDM-2026-03/04_03-2026.jpg",o="/aktivitaeten/BDM-2026-03/05_03-2026.jpg",g="/aktivitaeten/BDM-2026-03/06_03-2026.jpg",m="/aktivitaeten/BDM-2026-03/07_03-2026.jpg",p="/aktivitaeten/BDM-2026-03/08_03-2026.jpg",c="/aktivitaeten/BDM-2026-03/09_03-2026.jpg",_="/aktivitaeten/BDM-2026-03/10_03-2026.jpg",u="/aktivitaeten/BDM-2026-03/11_03-2026.jpg",h="/aktivitaeten/BDM-2026-03/12_03-2026.jpg",B="/aktivitaeten/BDM-2026-03/13_03-2026.jpg",M="/aktivitaeten/BDM-2026-03/14_03-2026.jpg",v="/aktivitaeten/BDM-2026-03/15_03-2026.jpg",k="/aktivitaeten/BDM-2026-03/16_03-2026.jpg",D="/aktivitaeten/BDM-2026-03/17_03-2026.jpg",b="/aktivitaeten/BDM-2026-03/18_03-2026.jpg",f="/aktivitaeten/BDM-2026-03/19_03-2026.jpg",j="/aktivitaeten/BDM-2026-03/20_03-2026.jpg",S="/aktivitaeten/BDM-2026-03/21_03-2026.jpg",z="/aktivitaeten/BDM-2026-03/22_03-2026.jpg",w="/aktivitaeten/BDM-2026-03/23_03-2026.jpg",A="/aktivitaeten/BDM-2026-03/24_03-2026.jpg",E="/aktivitaeten/BDM-2026-03/25_03-2026.jpg",F="/aktivitaeten/BDM-2026-03/26_03-2026.jpg",W="/aktivitaeten/BDM-2026-03/27_03-2026.jpg",H="/aktivitaeten/BDM-2026-03/28_03-2026.jpg",L="/aktivitaeten/BDM-2026-03/29_03-2026.jpg",T="/aktivitaeten/BDM-2026-03/30_03-2026.jpg",P="/aktivitaeten/BDM-2026-03/31_03-2026.jpg",O="/aktivitaeten/BDM-2026-03/32_03-2026.jpg",x="/aktivitaeten/BDM-2026-03/33_03-2026.jpg",N="/aktivitaeten/BDM-2026-03/34_03-2026.jpg",C="/aktivitaeten/BDM-2026-03/35_03-2026.jpg",Q="/aktivitaeten/BDM-2026-03/36_03-2026.jpg",G="/aktivitaeten/BDM-2026-03/37_03-2026.jpg",V="/aktivitaeten/BDM-2026-03/38_03-2026.jpg";const K={},R=a('<h1 id="bilder-des-monats-marz-2026" tabindex="-1"><a class="header-anchor" href="#bilder-des-monats-marz-2026" aria-hidden="true">#</a> Bilder des Monats M\xE4rz 2026</h1><p>Endlich kein Eis und Schnee mehr und so war ich zum ersten Mal in diesem Jahr wieder in meinem Hauspark. 73 DF9HC</p><p><img src="'+r+'" alt="Bilder des Monats"><img src="'+n+'" alt="Bilder des Monats"><img src="'+s+'" alt="Bilder des Monats"></p><p>Heute ging\u2019s zur Saarl\xE4ndischen Funkausstellung (SaFa) nach Dillingen</p><p>Erst ein bisschen \xFCber den Flohmarkt geschlendert, das ein oder andere Teil abgestaubt und viele nette Gespr\xE4che mit Funkfreunden gef\xFChrt. Zur St\xE4rkung gab\u2019s mittags ganz klassisch Erbsensuppe mit W\xFCrstchen \u2013 genau richtig bei dem Wetter</p><p>Am Nachmittag wurden dann die Bunker D/BL-0061, D/BL-0156, D/BL-0238, D/BL-0239 sowie der Park DE-0192 gemeinsam mit den OM\u2019s DK1TBL, DB6LX, DO5DOS und mir (DA6TW) aktiviert.</p><p>Danach ging es f\xFCr mich noch weiter nach Saarlouis. Dort habe ich zus\xE4tzlich die Parks DE-0152 und DE-0192 sowie den Bunker D/BL-0288 aktiviert. Auf SSB sind dabei noch 4 sch\xF6ne Park-to-Park-QSOs ins Log gekommen.</p><p><img src="'+d+'" alt="Bilder des Monats"><img src="'+l+'" alt="Bilder des Monats"></p><p>DF9HC auf kurzem Stop im Biosph\xE4renreservat Mittelelbe am sog. Schwedenhaus</p><p><img src="'+o+'" alt="Bilder des Monats"><img src="'+g+'" alt="Bilder des Monats"><img src="'+m+'" alt="Bilder des Monats"></p><p>Heute ging es nach F\xFCssen an den sch\xF6nen Forggensee ( ohne Wasser ) . Geplant war eine schnelle Feierabend Aktivierung von DE-0791 . Mit dabei war eigentlich alles , genutzt habe ich den QMX und die DF Vertical. Nach 31 Minuten waren 12 QSO s im Kasten. Sonnige Gr\xFC\xDFe aus dem Allg\xE4u</p><p>73 DL2MBN</p><p><img src="'+p+'" alt="Bilder des Monats"><img src="'+c+'" alt="Bilder des Monats"><img src="'+_+'" alt="Bilder des Monats"><img src="'+u+'" alt="Bilder des Monats"></p><p>Trotz schlechter Propagation raus getraut um den Park DE-0867 in CW zu aktivieren. Es war Sonnig gleichzeitig ging aber ein sehr kalter Wind , so das man beim geben auch gern mal das ein oder andere Zeichen v\xF6llig falsch gegeben hat wegen kalter Finger \u{1F604} . Trotz allem hab ich es in ca 43 Minuten mit 14 QSO s den Park geschafft zu aktivieren. Mit dabei waren der QMX und die DF Vertikal Antenne auf 20 Meter.</p><p>73 DL2MBN</p><p><img src="'+h+'" alt="Bilder des Monats"><img src="'+B+'" alt="Bilder des Monats"><img src="'+M+'" alt="Bilder des Monats"><img src="'+v+'" alt="Bilder des Monats"><img src="'+k+'" alt="Bilder des Monats"></p><p>Draussenfunken geht auch auf Fuerteventura. SSB Kontakte auf 10 + 15m nach Festland-Spanien, England, Sardinien, die Schweiz, Finnland, Benin, New York State und Uruguay mit nur 8W und l/4-Whip im Sand.</p><p>73 DE EA8/DA2JH</p><p><img src="'+D+'" alt="Bilder des Monats"><img src="'+b+'" alt="Bilder des Monats"></p><p>21.03.2026 - ein Blick am Morgen auf die Vorhersagen verhie\xDF nichts Gutes und die Entt\xE4uschung war anf\xE4nglich gro\xDF - alle B\xE4nder rot und noch chaotisch dazu. Doch das soll einen Drau\xDFenfunker aber nicht davon abhalten eine Aktivierung zu versuchen, zumal der Plan schon lange fest stand. Ziel war am Vormittag der Ort meiner allerersten POTA-Aktivierung, DE-0554 und DE-0740, der Rennsteig auf der H\xF6he von Eisenach. Mit dabei mein treuer FT-891 und eine xOTA-EFHW die sich anf\xE4nglich beharrlich weigerte im Baum zu bleiben und dazu ein ordentliches SWR abzuliefern. Kalt war es auch noch und zwischenzeitlich sa\xDF ich sogar in den Wolken. Aller Widrigkeiten zum Trotz wurde ich dann auf 40m mit einem pr\xE4chtigem Andrang belohnt. Nach gut zwei Stunden Betrieb konnten um die 80 SSB QSOs mit diversen Park to Parks im Log verbucht werden. Alles in Allem eine sehr sch\xF6ne POTA-Aktivierung - gerne wieder!</p><p>73 DL7LW</p><p><img src="'+f+'" alt="Bilder des Monats"><img src="'+j+'" alt="Bilder des Monats"><img src="'+S+'" alt="Bilder des Monats"><img src="'+z+'" alt="Bilder des Monats"><img src="'+w+'" alt="Bilder des Monats"><img src="'+A+'" alt="Bilder des Monats"><img src="'+E+'" alt="Bilder des Monats"><img src="'+F+'" alt="Bilder des Monats"></p><p>Antenne f\xFCr heutigen Warthog: DE-0004, DE-0009, DE-0599, DE-0960 und DE-0961: 3m whip f\xFCr 20 und 40m aufm Autodach. 73 de DJ2GMS</p><p><img src="'+W+'" alt="Bilder des Monats"></p><p>Und so sah das &quot;shack&quot;aus bei DJ2GMS</p><p><img src="'+H+'" alt="Bilder des Monats"></p><p>Holger, CB-Skip Die Erdbeere, DX-Rufzeichen 13-OT-4242 beim Draussenfunk im 11m-Band am Wilstedter See. Der Spiderbeam Mini 10m-Mast im HT-Rohr, welches gleichzeitig als Schutz beim Transport dient.</p><p>CB-Funk Skip: Rufname der Station.</p><p><img src="'+L+'" alt="Bilder des Monats"><img src="'+T+'" alt="Bilder des Monats"><img src="'+P+'" alt="Bilder des Monats"></p><p>Heute ging\u2019s nach dem kurzen Winter Einbruch wieder raus nach DE-0867. Die MUF lag bei &gt;23 MHz bei nem stabilen K Wert von 2 und A 6 + Fluxindex \xFCber 150. Die Aktivierung erfolge aus dem Auto raus da es doch noch sehr kalt drau\xDFen ist. Mit dabei waren das FT891 auf 40 Watt ( CW ) gestellt und ein simpler Hamstick auf dem Autodach f\xFCr das 20 Meter Band. Als Stromversorgung war meine selbst gebaute Akku Box dabei mit einem 100 Ah Akku. Mit dem h\xE4tte ich wohl die n\xE4chsten 2 Tage Funken k\xF6nnen \u{1F604} . So ergaben sich 41 qsos in einer Stunde CQ rufen . Meine pers\xF6nlichen Highlight waren 2 \xDCbersee Verbindungen nach Amerika. Danke an alle Hunter und Aktivierer die dieses tolle Programm am Leben halten. 73 DL2MBN</p><p><img src="'+O+'" alt="Bilder des Monats"><img src="'+x+'" alt="Bilder des Monats"><img src="'+N+'" alt="Bilder des Monats"><img src="'+C+'" alt="Bilder des Monats"><img src="'+Q+'" alt="Bilder des Monats"><img src="'+G+'" alt="Bilder des Monats"><img src="'+V+'" alt="Bilder des Monats"></p>',31),J=[R];function X(q,U){return i(),t("div",null,J)}var y=e(K,[["render",X],["__file","2026-03-30-Bilder-Des-Monats-M\xE4rz.html.vue"]]);export{y as default};
